// ── Shared interfaces (re-exported from learn bank if needed) ──

export interface LearnStep {
  step: number;
  title_en: string;
  title_ar: string;
  explanation_en: string;
  explanation_ar: string;
}

export interface LearnMethod {
  steps: LearnStep[];
  hint_en: string;
  hint_ar: string;
  result_en: string;
  result_ar: string;
}

export interface PracticeMeta {
  fun_fact_tag: string;
}

// ── Light problem (common bank: Add/Sub/Mul/Div) ──
export interface LightPracticeProblem {
  id: string;
  grade: number;
  bank: 'common';
  category: 'Addition' | 'Subtraction' | 'Multiplication' | 'Division';
  level: 'Easy' | 'Medium' | 'Hard';
  question_en: string;
  question_ar: string;
  answer: number;
  learn_ref: string;  // ID in grade8LearnBank to show steps on 2-mistake trigger
}

// ── Full problem (specific bank: Powers/Sci/Word) ──
export interface FullPracticeProblem {
  id: string;
  grade: number;
  bank: 'specific';
  category: 'Powers & Roots' | 'Scientific Notation' | 'Word Problem';
  level: 'Easy' | 'Medium' | 'Hard';
  question_en: string;
  question_ar: string;
  answer: number;
  methods: {
    vedic: LearnMethod;
    decompose: LearnMethod;
    visualize: LearnMethod;
  };
  meta: PracticeMeta;
}

export type PracticeProblem = LightPracticeProblem | FullPracticeProblem;

