// ── Helper functions ──
export const getByCategory = (cat: string) =>
  grade8PracticeBank.filter(p => p.category === cat);

export const getByLevel = (level: 'Easy' | 'Medium' | 'Hard') =>
  grade8PracticeBank.filter(p => p.level === level);

export const getById = (id: string) =>
  grade8PracticeBank.find(p => p.id === id) ?? null;

export const getLightProblems = () =>
  grade8PracticeBank.filter((p): p is LightPracticeProblem => p.bank === 'common');

export const getFullProblems = () =>
  grade8PracticeBank.filter((p): p is FullPracticeProblem => p.bank === 'specific');
